class Solution:
    def minimumBeautifulSubstrings(self, s: str) -> int:
        from functools import lru_cache

        # Precompute all powers of 5 in binary form up to length 15
        powers_of_5 = set()
        for i in range(0, 16):  # 5^0 to 5^15
            power = 5 ** i
            binary = bin(power)[2:]
            powers_of_5.add(binary)

        n = len(s)

        @lru_cache(None)
        def dp(i):
            if i == n:
                return 0
            res = float('inf')
            for j in range(i + 1, n + 1):
                substring = s[i:j]
                if substring[0] == '0':
                    continue  # Skip substrings with leading zeros
                if substring in powers_of_5:
                    res = min(res, 1 + dp(j))
            return res

        result = dp(0)
        return result if result != float('inf') else -1
